metadata.css_recomendado:
.comustock-downloads {
  display: grid;
  gap: 16px;
}

.comustock-download-card {
  position: relative;
  display: grid;
  gap: 10px;
  padding: 16px;
  border: 1px solid rgba(5, 44, 80, 0.18);
  border-radius: 18px;
  background: var(--bg, #ffffff);
}

.comustock-download-card__title {
  margin: 0;
  font-size: 1rem;
  line-height: 1.25;
  color: #052c50;
}

.comustock-download-card__links {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.comustock-download-link {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  min-height: 38px;
  padding: 8px 12px;
  border: 2px solid #052c50;
  border-radius: 14px;
  background: var(--bg, #ffffff);
  color: #052c50;
  text-decoration: none;
  font-weight: 600;
  line-height: 1;
  transition:
    background-color 220ms ease,
    border-color 220ms ease,
    color 220ms ease,
    box-shadow 220ms ease,
    transform 220ms ease;
}

.comustock-download-link:hover,
.comustock-download-link:focus-visible {
  background: #d10097;
  border-color: #d10097;
  color: #ffffff;
  box-shadow: 0 8px 18px rgba(209, 0, 151, 0.24);
  outline: none;
  transform: translateY(-1px);
}

.download-link__icon {
  width: 16px;
  height: 16px;
  fill: currentColor;
  flex: 0 0 auto;
}

